        "TLS"
      ],
      "distractors": [
        "DNS",
        "HTML",
        "HTTP",
        "rendering"
      ],
      "feedback": "TCP provides the transport connection. TLS runs on top of that connection to authenticate and encrypt the HTTP exchange."
    },
